css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 220px; background: #0f1320; border-right: 1px solid rgba(255,255,255,0.06); padding: 28px 18px; flex-shrink: 0; }
.logo { font-size: 18px; font-weight: 800; margin-bottom: 32px; padding-left: 8px; }
nav { display: flex; flex-direction: column; gap: 4px; }
nav a { display: flex; align-items: center; gap: 12px; padding: 11px 12px; border-radius: 10px; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; }
nav a span { font-size: 16px; }
nav a.active { background: rgba(249,115,22,0.12); color: #fb923c; }
.content { flex: 1; padding: 32px 36px; max-width: 1100px; }
header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 26px; flex-wrap: wrap; gap: 12px; }
header h1 { font-size: 26px; font-weight: 800; }
header p { color: rgba(255,255,255,0.4); font-size: 13px; margin-top: 4px; }
.period { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); padding: 9px 16px; border-radius: 10px; font-size: 13px; font-weight: 600; color: rgba(255,255,255,0.7); }
.stats { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 14px; margin-bottom: 22px; }
.stat { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px 20px; display: flex; flex-direction: column; gap: 6px; }
.stat .label { color: rgba(255,255,255,0.4); font-size: 12.5px; font-weight: 600; }
.stat .value { font-size: 24px; font-weight: 800; }
.delta { font-size: 12px; font-weight: 700; width: fit-content; padding: 2px 8px; border-radius: 999px; }
.delta.up { color: #4ade80; background: rgba(74,222,128,0.12); }
.delta.down { color: #f87171; background: rgba(248,113,113,0.12); }
.grid { display: grid; grid-template-columns: 1.6fr 1fr; gap: 16px; margin-bottom: 16px; }
.panel { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 22px; }
.panel-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; }
.panel-head h2 { font-size: 15px; font-weight: 700; }
.badge { background: rgba(249,115,22,0.12); color: #fb923c; font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 999px; }
.chart-panel .bars { display: flex; align-items: flex-end; gap: 10px; height: 140px; }
.bar { flex: 1; background: rgba(255,255,255,0.08); border-radius: 8px 8px 0 0; }
.bar.active { background: linear-gradient(180deg, #fb923c, #f97316); }
.bar-labels { display: flex; gap: 10px; margin-top: 10px; }
.bar-labels span { flex: 1; text-align: center; font-size: 11px; color: rgba(255,255,255,0.35); }
.product-list { display: flex; flex-direction: column; gap: 14px; }
.product { display: flex; align-items: center; gap: 12px; }
.thumb { width: 38px; height: 38px; border-radius: 10px; background: rgba(255,255,255,0.06); display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; }
.pinfo { display: flex; flex-direction: column; gap: 2px; flex: 1; }
.pname { font-size: 13.5px; font-weight: 600; }
.psold { font-size: 11.5px; color: rgba(255,255,255,0.4); }
.prevenue { font-size: 13px; font-weight: 700; color: #fb923c; }
table { width: 100%; border-collapse: collapse; }
th { text-align: left; font-size: 11.5px; color: rgba(255,255,255,0.4); font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; padding: 0 0 12px; }
td { padding: 12px 0; font-size: 13.5px; border-top: 1px solid rgba(255,255,255,0.05); }
.status { padding: 4px 12px; border-radius: 999px; font-size: 11.5px; font-weight: 700; }
.status.delivered { background: rgba(74,222,128,0.12); color: #4ade80; }
.status.shipped { background: rgba(99,102,241,0.12); color: #818cf8; }
.status.processing { background: rgba(234,179,8,0.12); color: #facc15; }
@media (max-width: 800px) { .layout { flex-direction: column; } .sidebar { width: 100%; display: flex; } nav { flex-direction: row; overflow-x: auto; } .grid { grid-template-columns: 1fr; } }

